297	// deno-lint-ignore no-explicit-any -- supabase-js generic args differ
298	// between the createClient call above (inferred as public schema) and
299	// any helper import; typing loosely avoids a widening mismatch.
300	async function fetchLatestFreshSnapshots(
301	  supabase: any,
302	  socialLinkId: string,
303	  requiredModes: Array<"tiktok_profile" | "ig_details" | "ig_posts">,
304	  cutoffIso: string,
