332	// deno-lint-ignore no-explicit-any -- see note above on supabase-js generics
333	async function computeRetryAfterSec(
334	  supabase: any,
335	  socialLinkId: string,
336	  nowMs: number,
337	): Promise<number> {
338	  const { data, error } = await supabase
339	    .from("social_links")
