    paddingHorizontal: spacing.md,
    paddingVertical: 4,
  },
  signOutWrap: {
    paddingTop: spacing.md,
  },
  sheetBody: {
    gap: spacing.base,
  },
  sheetHint: {
    color: colors.ink70,
  },
  inputWrap: {
